INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-6f0ba476-moex-00015', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日購入一棟辦公大樓，並將之分類為投資性不動產，支付總成本為$10,500,000。 其中，建築物成本為$3,500,000（估計使用年限為25年，無殘值），土地成本為$7,000,000。 甲公司於X1年7月1日以營業租賃方式出租該辦公大樓，每月租金$60,000。甲公司以公允 價值模式衡量投資性不動產，X1年底，該辦公大樓之土地公允價值為$7,400,000、建築物公允 價值為$3,200,000。若不考慮所得稅，該投資性不動產對X1年度之本期損益的影響為多少？', '["本期淨利減少$80,000", "本期淨利增加$220,000", "本期淨利增加$320,000", "本期淨利增加$460,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00016', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '依依公司在編製X5年10月份銀行調節表時，銀行存款資料如下： 10月31日銀行對帳單餘額 $553,000 10月31日存款不足退票 12,400 10月31日未兌現支票 42,900 10月31日在途存款 62,600 10月份銀行手續費 1,800 則依依公司X5年10月31日調整前公司帳載存款餘額為何？', '["$533,300", "$558,500", "$572,700", "$586,900"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00017', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '爾爾公司因需要額外資金，決定利用下列應收帳款之交易獲取所需之現金：', '["X5年9月15日爾爾公司以$600,000應收帳款向珊珊銀行進行擔保借款，借款金額為擔保 應收帳款總額的80%，珊珊銀行收取借款金額的3%作為財務費用，在X5年12 月31日 前，該筆應收帳款已收現$400,000，同時爾爾公司償付珊珊銀行$432,000（包含$32,000的 利息費用），並攤銷80%之財務費用", "X5 年 10 月 1 日，爾爾公司另以無追索權方式出售應收帳款給寺寺銀行，並取得現金 $750,000（寺寺銀行未保留應收帳款作為銷貨退回及折讓之沖抵）。 上述交易對於爾爾公司X5年損益表之影響為費損$93,520，試問爾爾公司出售給寺寺銀行之 應收帳款金額為何？", "$700,000", "$800,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00018', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '巴巴公司X3/9/1以$500,000購入一項設備，估計耐用年限10年，殘值$20,000，並以直線法 提列折舊。X5/1/1，巴巴公司將此項設備改以倍數餘額遞減法提列折舊，殘值變更為$43,600， X5年折舊費用為$174,400，試問決定改變折舊方法時估計耐用年限尚有幾年？', '["2.5年", "4.5年", "4.77年", "5年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00019', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '久久公司X5年5月1日開始建造工廠，該工廠經一段相當長的期間始達到預定使用狀態， 久久公司於X5年8月1日為建造廠房而支付工程款$20,000,000，並向玲玲銀行辦理專案廠 房貸款$15,000,000，期間二年，年利率10%，經分析若該企業不建造該廠房，則無須負擔上 述借款之利息。其他借款資訊包含 X5 年 7 月 1 日久久公司平價發行一無擔保之商業本票 $6,000,000，期間6個月、年利率12%，以及久久公司於X1年8月1日向租賃公司以融資租 賃方式承租建廠混凝土卡車一輛，X1年8月1日租賃負債為$600,000，8月份隱含利息支出 $19,200。試求久久公司於該工程中X5年8月份可資本化之借款成本為多少？', '["$60,000", "$125,000", "$175,000", "$185,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00020', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '依珊公司於X2年初購入一項專利權，成本$8,000,000，法定年限為10年，估計經濟年限為 5年。X4年初，專利權發生侵權官司，依珊公司於該年11月1日獲得勝訴，使專利權之效 益得以維持，而X4年底支付是項訴訟費$500,000。試問依珊公司X5年底專利權之帳面金額 為多少？', '["$1,600,000", "$1,850,000", "$3,200,000", "$3,700,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00021', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '依武公司每年均提撥考量紅利及所得稅後盈餘之20%作為員工績效獎金，若今年稅前及減除 獎金前之盈餘為$500,000，公司所得稅率為15%，試問員工獎金為何？', '["$64,103", "$72,650", "$83,333", "$100,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00022', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '依巴公司於某年初發行面額$1,000,000，年息6%，每年6月30日及12月31日付息之公司 債一批，發行時有效利率為 8%，公司債溢折價攤銷均採有效利息法。該公司債之到期日為 114年12月31日，則此應付公司債在113年12月31日之帳面金額應為若干？', '["$970,251", "$963,696", "$981,139", "$972,249"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00023', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '依玲公司X5年度歸屬於母公司業主之稅後淨利為$500,000，該公司X5年度有下列形式上為', '["特別股Y，面額及帳面金額均為$400,000，股利率6%，不可賣回且股利 非累積。X5年7月1日公司在公開市場以折價$50,000買回面額$200,000之特別股", "特別 股Z，面額$300,000之累積且可轉換之特別股，股利率6%。依玲公司於X5年12月31日誘 導投資人轉換，額外發行公允價值總值$50,000之普通股。公司於X5年並未宣告特別股Y、 Z之股利。依玲公司X5年在計算基本每股盈餘時，所用分子之金額為何？", "$382,000", "$482,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00024', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '爾寺公司X5年度應收帳款（淨額）之期初與期末餘額分別為$68,000、$104,000，預收收入之 期初與期末餘額分別為$20,000、$50,000。當年度銷貨收入$1,000,000、認列預期信用減損損 失$60,000，期初備抵損失餘額為$0，則該公司當年度自銷貨收到之現金金額為多少？', '["$934,000", "$946,000", "$994,000", "$1,054,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
